const req = $json;
const body = req.body || req || {};
const errors = [];
const required = ['workspace_id', 'campaign_id', 'task_type', 'prompt'];
for (const key of required) {
  if (body[key] === undefined || body[key] === null || body[key] === '') errors.push('Missing required field: ' + key);
}
const allowed = ['image_generation'];
if (body.task_type && !allowed.includes(String(body.task_type))) errors.push('task_type must be one of: ' + allowed.join(', '));
return [{
  json: {
    workspace_id: body.workspace_id || null,
    campaign_id: body.campaign_id || null,
    task_type: body.task_type || null,
    prompt: body.prompt || '',
    constraints: body.constraints || {},
    valid_request: errors.length === 0,
    validation_errors: errors,
    received_at: new Date().toISOString()
  }
}];

const payload = $json;
const row = $json || {};
const parseJsonLike = (v, fallback) => {
  if (v === null || v === undefined) return fallback;
  if (typeof v === 'string') {
    try { return JSON.parse(v); } catch (e) { return fallback; }
  }
  return v;
};
const requestConstraints = parseJsonLike(payload.constraints, {});
const constraints = requestConstraints && Object.keys(requestConstraints).length ? requestConstraints : parseJsonLike(row.constraints_json, {});
return [{
  json: {
    ...payload,
    campaign_strategy: parseJsonLike(row.campaign_strategy, {}),
    strategy_json: parseJsonLike(row.strategy_json, {}),
    constraints_json: constraints,
    winning_tones_json: parseJsonLike(row.winning_tones_json, {}),
    winning_channels_json: parseJsonLike(row.winning_channels_json, {}),
    media_seed: Date.now(),
    ai_provider: { image: 'pollinations' },
  }
}];

const base = $node['W4 Build Task Context'].json;
const probeFailed = Boolean($json.error);
const aiPrompt = String(base.prompt || '') + ', ' + String(base.constraints_json?.style || 'cinematic') + ', ultra-detailed';
const mediaUrl = 'https://image.pollinations.ai/prompt/' + encodeURIComponent(aiPrompt) + '?width=1024&height=1024&nologo=true&seed=' + String(base.media_seed || Date.now());
return [{
  json: {
    ...base,
    media_type: 'image',
    channel: base.constraints_json?.channel || null,
    status: 'ready',
    media_url: mediaUrl,
    job_id: null,
    provider_payload_json: $json,
    error_message: probeFailed ? String($json.error.message || 'image_provider_probe_failed') : null,
    insight_type: 'image_generation',
    insight_json: { prompt: base.prompt, constraints: base.constraints_json || {}, ai_provider: 'pollinations-image' }
  }
}];
